mapper.select:
SELECT m.user_id AS userId, MAX(m.created_at) AS lastMsgTime
FROM cs_message m
WHERE m.created_at >= #{since}
GROUP BY m.user_id
ORDER BY lastMsgTime DESC
LIMIT #{limit}

SELECT m.user_id AS userId, MAX(m.created_at) AS lastMsgTime
FROM cs_message m
WHERE m.agent_id = #{agentId}
  AND m.created_at >= #{since}
GROUP BY m.user_id
ORDER BY lastMsgTime DESC
LIMIT #{limit}
